import React, { Component, ErrorInfo, ReactNode } from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { Activity } from 'lucide-react';

interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

// --- ERROR BOUNDARY ---
class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null
    };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught Error in React Tree:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ 
          height: '100vh', 
          width: '100vw', 
          backgroundColor: '#000000', 
          color: '#ffffff', 
          display: 'flex', 
          flexDirection: 'column', 
          alignItems: 'center', 
          justifyContent: 'center', 
          padding: '24px',
          textAlign: 'center', 
          fontFamily: 'sans-serif' 
        }}>
          <div style={{ marginBottom: '24px', opacity: 0.5 }}>
            <Activity size={48} color="#CEF245" />
          </div>
          <h1 style={{ fontSize: '20px', marginBottom: '12px', fontWeight: 800, letterSpacing: '0.1em', color: '#CEF245' }}>RECOVERY MODE</h1>
          <p style={{ color: '#9ca3af', maxWidth: '300px', fontSize: '12px', lineHeight: '1.5', marginBottom: '32px' }}>
             The system encountered an unexpected anomaly. We have stabilized the interface.
          </p>
          <button 
            onClick={() => {
                this.setState({ hasError: false, error: null });
                window.location.reload();
            }}
            style={{ 
              padding: '16px 32px', 
              background: 'rgba(255,255,255,0.1)', 
              color: 'white', 
              border: '1px solid rgba(255,255,255,0.2)', 
              borderRadius: '9999px',
              fontWeight: 700,
              fontSize: '12px',
              letterSpacing: '0.2em',
              cursor: 'pointer',
              textTransform: 'uppercase'
            }}
          >
            Reboot System
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

// --- ORIENTATION LOCK IMPLEMENTATION ---
const lockOrientation = async () => {
  const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
  // @ts-ignore
  if (isMobile && screen.orientation && typeof screen.orientation.lock === 'function') {
    try {
      // @ts-ignore
      await screen.orientation.lock('portrait');
    } catch (error) {
      console.debug("Orientation lock skipped:", error);
    }
  }
};

// Attempt lock on initialization without blocking
lockOrientation().catch(() => {});

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  );
}

import { createClient, type User } from '@supabase/supabase-js';
import { ActivityData, UserMetrics, UserProfile, DailyActivityDB, FoodLogDB, ChatHistoryDB } from '../types';

export type { User } from '@supabase/supabase-js';

// --- CONFIGURATION ---
const SUPABASE_URL = 'https://rkalxppxkphbddmmozbl.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_GmjutU13Q02MxGsCWaB2lA_ymuPyX1I';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
  auth: {
    detectSessionInUrl: false,
    persistSession: true,
    autoRefreshToken: true,
  }
});

export const DEFAULT_AVATAR = "https://upload.wikimedia.org/wikipedia/commons/8/89/Portrait_Placeholder.png";

// --- DATE HELPER (CRITICAL FOR MIDNIGHT RESET) ---
// Returns YYYY-MM-DD based on Local Device Time, not UTC.
export const getLocalTodayKey = (): string => {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// --- GUEST MODE HELPERS ---
const GUEST_ID_PREFIX = 'guest_';
const isGuest = (userId: string) => userId.startsWith(GUEST_ID_PREFIX);

export const signInAsGuest = () => {
  const guestId = GUEST_ID_PREFIX + Math.random().toString(36).substr(2, 9);
  const guestUser: any = {
    id: guestId,
    email: 'guest@healthyhub.elite',
    user_metadata: { full_name: 'Elite Guest' },
    is_guest: true
  };
  localStorage.setItem('healthy_hub_guest_session', JSON.stringify(guestUser));
  window.dispatchEvent(new Event('guest_auth_change'));
  return guestUser;
};

export const getGuestSession = () => {
  const stored = localStorage.getItem('healthy_hub_guest_session');
  return stored ? JSON.parse(stored) : null;
};

export const clearGuestSession = () => {
  localStorage.removeItem('healthy_hub_guest_session');
  window.dispatchEvent(new Event('guest_auth_change'));
};

// --- CORE FUNCTIONALITY ---

export const syncDailyActivity = async (userId: string, steps: number, calories: number, stepGoal: number, distanceKm: number = 0) => {
  if (isGuest(userId)) {
    const localData = JSON.parse(localStorage.getItem(`activity_${userId}_today`) || '{}');
    localData.steps = steps;
    localData.calories_burned = calories;
    localData.distance_km = distanceKm;
    localData.is_target_met = steps >= stepGoal;
    localData.updated_at = new Date().toISOString();
    localStorage.setItem(`activity_${userId}_today`, JSON.stringify(localData));
    return;
  }

  const todayKey = getLocalTodayKey();
  const isTargetMet = steps >= stepGoal;

  try {
    // Upsert using the LOCAL date key to ensure persistence for the correct day
    const { error } = await supabase.from('daily_activity').upsert({ 
      user_id: userId, 
      activity_date: todayKey, 
      steps: steps, 
      calories_burned: calories, 
      distance_km: distanceKm,
      is_target_met: isTargetMet,
      updated_at: new Date().toISOString()
    }, { 
      onConflict: 'user_id, activity_date' 
    });

    if (error) throw error;
  } catch (e) {
    console.error("Cloud Sync Error:", e);
    throw e;
  }
};

export const fetchFullUserDashboard = async (userId: string) => {
  if (isGuest(userId)) {
    const storedProfile = localStorage.getItem(`profile_${userId}`);
    if (!storedProfile) return null;
    return {
      profile: JSON.parse(storedProfile),
      todayActivity: JSON.parse(localStorage.getItem(`activity_${userId}_today`) || 'null'),
      foodLogs: [],
      chatHistory: []
    };
  }
  try {
    const todayKey = getLocalTodayKey();

    const { data: profileData, error: profileError } = await supabase.from('profiles').select('*').eq('id', userId).maybeSingle();
    if (profileError || !profileData) return null; 

    const [activityRes, foodRes, chatRes] = await Promise.all([
      // Fetch specifically for the LOCAL date. If midnight passed, this returns null (Reset Logic)
      supabase.from('daily_activity').select('*').eq('user_id', userId).eq('activity_date', todayKey).maybeSingle(),
      supabase.from('food_logs').select('*').eq('user_id', userId).order('created_at', { ascending: false }).limit(20),
      supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(50)
    ]);

    return {
      profile: mapProfileToAppFormat(profileData),
      todayActivity: activityRes.data as any | null,
      foodLogs: foodRes.data as FoodLogDB[] || [],
      chatHistory: chatRes.data as ChatHistoryDB[] || []
    };
  } catch (e) {
    return null;
  }
};

export const checkAndUpdateStreak = async (userId: string, currentStepGoal: number) => {
  if (isGuest(userId)) return 1;

  // Calculate yesterday in Local Time
  const today = new Date();
  const yesterday = new Date(today);
  yesterday.setDate(today.getDate() - 1);

  const yYear = yesterday.getFullYear();
  const yMonth = String(yesterday.getMonth() + 1).padStart(2, '0');
  const yDay = String(yesterday.getDate()).padStart(2, '0');
  const yesterdayKey = `${yYear}-${yMonth}-${yDay}`;

  try {
    const { data: profile } = await supabase.from('profiles').select('current_streak').eq('id', userId).maybeSingle();
    let streak = profile?.current_streak || 0;

    const { data: yesterdayActivity } = await supabase.from('daily_activity').select('is_target_met').eq('user_id', userId).eq('activity_date', yesterdayKey).maybeSingle();

    // Logic: If yesterday exists but target not met -> Reset. If yesterday missing -> Reset (unless streak is 0).
    if (!yesterdayActivity || !yesterdayActivity.is_target_met) {
       if (streak > 0) {
          // Double check if *today* is already met (edge case) before resetting hard? 
          // For now, strict strict rules: Miss a day = Reset.
          streak = 0;
          await supabase.from('profiles').update({ current_streak: 0 }).eq('id', userId);
       }
    }
    return streak;
  } catch (e) {
    return 0;
  }
};

export const fetchStreakCalendarData = async (userId: string) => {
  if (isGuest(userId)) return { joinDate: new Date().toISOString(), streakDates: [] };
  try {
      const { data: profile } = await supabase.from('profiles').select('created_at').eq('id', userId).maybeSingle();
      const { data: logs } = await supabase.from('daily_activity').select('activity_date').eq('user_id', userId).eq('is_target_met', true);
      return { 
        joinDate: profile?.created_at || new Date().toISOString(), 
        streakDates: logs?.map(l => l.activity_date) || [] 
      };
  } catch (e) {
      return { joinDate: new Date().toISOString(), streakDates: [] };
  }
};

export const fetchChatHistory = async (userId: string): Promise<ChatHistoryDB[]> => {
  if (isGuest(userId)) return [];
  const { data, error } = await supabase.from('chat_history').select('*').eq('user_id', userId).order('created_at', { ascending: true }).limit(100);
  if (error) return [];
  return data as ChatHistoryDB[];
};

export const saveChatMessage = async (userId: string, message: string, isUserMessage: boolean, planData?: any) => {
  if (isGuest(userId)) return;
  await supabase.from('chat_history').insert({ user_id: userId, message, is_user_message: isUserMessage, plan_data: planData });
};

export const completeOnboarding = async (user: User, profileData: UserProfile, activityGoals: ActivityData) => {
  const initialData = {
    id: user.id, 
    email: user.email,
    name: profileData.name,
    avatar_url: profileData.avatarUrl || DEFAULT_AVATAR,
    current_streak: 0,
    daily_step_goal: activityGoals.stepGoal,
    daily_calorie_goal: activityGoals.calorieGoal,
    goals: {
        stepGoal: activityGoals.stepGoal,
        calorieGoal: activityGoals.calorieGoal,
        distanceGoal: activityGoals.distanceGoal
    },
    metrics: profileData.metrics,
    weight: profileData.metrics?.weight,
    height: profileData.metrics?.height,
    bmi: (profileData.metrics?.weight || 0) / (((profileData.metrics?.height || 100)/100) ** 2),
    created_at: new Date().toISOString()
  };

  if (isGuest(user.id)) {
    const formattedProfile = mapProfileToAppFormat(initialData);
    localStorage.setItem(`profile_${user.id}`, JSON.stringify(formattedProfile));
    return formattedProfile;
  }

  const { error } = await supabase.from('profiles').upsert(initialData);
  if (error) throw new Error(`Database Save Failed: ${error.message}`);
  return mapProfileToAppFormat(initialData);
};

const mapProfileToAppFormat = (dbProfile: any): UserProfile => {
  const safeGoals = dbProfile.goals || {};
  const safeMetrics = dbProfile.metrics || {};
  return {
    id: dbProfile.id,
    name: dbProfile.name || 'Elite Member',
    email: dbProfile.email || '',
    avatarUrl: dbProfile.avatar_url || dbProfile.avatarUrl || DEFAULT_AVATAR,
    currentStreak: dbProfile.current_streak || 0,
    currentPlanName: dbProfile.current_plan_name,
    goals: {
        stepGoal: dbProfile.daily_step_goal || safeGoals.stepGoal || 10000,
        calorieGoal: dbProfile.daily_calorie_goal || safeGoals.calorieGoal || 2000,
        distanceGoal: Number(safeGoals.distanceGoal) || 5.0
    },
    metrics: {
        height: dbProfile.height || Number(safeMetrics.height) || 0,
        weight: dbProfile.weight || Number(safeMetrics.weight) || 0,
        age: Number(safeMetrics.age) || 25,
        gender: safeMetrics.gender || 'Other',
        dob: safeMetrics.dob || '',
        activityLevel: safeMetrics.activityLevel || 'Moderately Active',
        fitnessGoal: safeMetrics.fitnessGoal || 'Maintain',
        lastWeightUpdate: Number(safeMetrics.lastWeightUpdate) || Date.now(),
        lastHeightUpdate: Number(safeMetrics.lastHeightUpdate) || Date.now()
    }
  };
};

export const checkUserProfile = async (uid: string) => {
    if (isGuest(uid)) {
        const stored = localStorage.getItem(`profile_${uid}`);
        return stored ? JSON.parse(stored) : null;
    }
    try {
        const { data, error } = await supabase.from('profiles').select('*').eq('id', uid).maybeSingle();
        if (error) return null;
        return data ? mapProfileToAppFormat(data) : null;
    } catch (e) {
        return null;
    }
};

export const onAuthStateChanged = (callback: (user: User | null) => void) => {
  const checkGuest = () => {
    const guest = getGuestSession();
    if (guest) callback(guest);
  };

  const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
    if (session?.user) {
        clearGuestSession();
        callback(session.user);
    } else {
        const guest = getGuestSession();
        callback(guest);
    }
  });

  window.addEventListener('guest_auth_change', checkGuest);
  checkGuest();

  return () => {
      subscription.unsubscribe();
      window.removeEventListener('guest_auth_change', checkGuest);
  };
};

export const signInWithEmailAndPassword = async (email: string, psw: string) => {
  const { data, error } = await supabase.auth.signInWithPassword({ email, password: psw });
  if (error) throw error;
  return data;
};

export const signOut = async () => {
  await supabase.auth.signOut();
  clearGuestSession();
};

export const updateProfile = async (user: User, profile: { displayName?: string, photoURL?: string }) => {
    if (isGuest(user.id)) {
        const stored = JSON.parse(localStorage.getItem(`profile_${user.id}`) || '{}');
        if (profile.displayName) stored.name = profile.displayName;
        if (profile.photoURL) stored.avatarUrl = profile.photoURL;
        localStorage.setItem(`profile_${user.id}`, JSON.stringify(stored));
        return;
    }

    const authUpdates: any = {};
    if (profile.displayName) authUpdates.data = { ...authUpdates.data, full_name: profile.displayName };
    if (profile.photoURL) authUpdates.data = { ...authUpdates.data, avatar_url: profile.photoURL };
    if (Object.keys(authUpdates).length > 0) await supabase.auth.updateUser(authUpdates);

    const dbUpdates: any = {};
    if (profile.displayName) dbUpdates.name = profile.displayName;
    if (profile.photoURL) dbUpdates.avatar_url = profile.photoURL;
    if (Object.keys(dbUpdates).length > 0) {
        await supabase.from('profiles').update(dbUpdates).eq('id', user.id);
    }
};

export const updateUserMetrics = async (uid: string, metrics: UserMetrics) => {
  if (isGuest(uid)) {
    const stored = JSON.parse(localStorage.getItem(`profile_${uid}`) || '{}');
    stored.metrics = metrics;
    localStorage.setItem(`profile_${uid}`, JSON.stringify(stored));
    return;
  }
  await supabase.from('profiles').update({ 
      metrics,
      weight: metrics.weight,
      height: metrics.height,
      bmi: metrics.weight / ((metrics.height/100) ** 2)
  }).eq('id', uid);
};

export const updateUserTargets = async (userId: string, targets: { calories?: number, steps?: number, plan_name?: string }) => {
  if (isGuest(userId)) return;
  const updates: any = {};
  if (targets.calories !== undefined) updates.daily_calorie_goal = targets.calories;
  if (targets.steps !== undefined) updates.daily_step_goal = targets.steps;
  if (targets.plan_name !== undefined) updates.current_plan_name = targets.plan_name;

  const { data: profile } = await supabase.from('profiles').select('goals').eq('id', userId).maybeSingle();
  const currentGoals = profile?.goals || {};

  updates.goals = {
    ...currentGoals,
    stepGoal: targets.steps ?? currentGoals.stepGoal,
    calorieGoal: targets.calories ?? currentGoals.calorieGoal
  };

  await supabase.from('profiles').update(updates).eq('id', userId);
};

