      const { data: logs } = await supabase.from('daily_activity').select('activity_date').eq('user_id', userId).eq('is_target_met', true);
      return { 
        joinDate: profile?.created_at || new Date().toISOString(), 
        streakDates: logs?.map(l => l.activity_date) || [] 
      };
  } catch (e) {
      return { joinDate: new Date().toISOString(), streakDates: [] };
  }
};

