const ProgressRing: React.FC<{ 
  progress: number; 
  color: string; 
  icon: React.ReactNode;
  size?: number;
  strokeWidth?: number;
}> = ({ progress, color, icon, size = 100, strokeWidth = 8 }) => {
  const radius = (size / 2) - (strokeWidth * 1.5); 
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (Math.min(100, progress) / 100) * circumference;
  const center = size / 2;

  return (
    <div 
      className="relative flex items-center justify-center p-[10px]"
      style={{ width: size + 20, height: size + 20 }}
    >
      <svg 
        width={size} 
        height={size} 
        viewBox={`0 0 ${size} ${size}`} 
        className="-rotate-90 overflow-visible"
      >
        <circle 
          cx={center} 
          cy={center} 
          r={radius} 
          stroke="rgba(255,255,255,0.1)" 
          strokeWidth={strokeWidth} 
          fill="transparent" 
        />
        <motion.circle 
          cx={center} 
          cy={center} 
          r={radius} 
          stroke={color} 
          strokeWidth={strokeWidth} 
          fill="transparent" 
          strokeDasharray={circumference} 
          initial={{ strokeDashoffset: circumference }}
          animate={{ strokeDashoffset: offset }}
          strokeLinecap="round"
          className="transition-all duration-1000 ease-out"
          style={{ filter: `drop-shadow(0 0 8px ${color}44)` }}
        />
      </svg>
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <div className="text-white">
          {icon}
        </div>
      </div>
    </div>
  );
};

